<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Conway's Game of Life</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background-color: #121212;
            color: #ffffff;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
        }

        .container {
            width: 800px;
            height: 600px;
            background-color: #333;
            border-radius: 10px;
            box-shadow: 0 4px 20px rgba(0,0,0,0.5);
            padding: 20px;
            display: flex;
            justify-content: center;
            align-items: center;
        }

        canvas {
            background-color: #444;
            border-radius: 8px;
            margin-bottom: 10px;
        }

        h1 {
            font-size: 24px;
            text-align: center;
            margin-bottom: 20px;
        }

        .controls {
            display: flex;
            justify-content: space-between;
            align-items: center;
            background-color: #555;
            padding: 10px 15px;
            border-radius: 5px;
            margin-top: 10px;
        }

        button {
            background-color: #4CAF50;
            color: white;
            border: none;
            padding: 8px 12px;
            font-size: 14px;
            cursor: pointer;
            transition: background-color 0.3s;
        }

        button:hover {
            background-color: #45a049;
        }

        .grid-controls {
            display: flex;
            gap: 10px;
            margin-top: 15px;
        }

        .step-btn, .play-btn, .clear-btn {
            width: 60px;
            height: 60px;
            border-radius: 50%;
            cursor: pointer;
            background-color: #333;
            color: white;
            display: flex;
            align-items: center;
            justify-content: center;
        }

        .step-btn:hover, .play-btn:hover, .clear-btn:hover {
            background-color: #555;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Conway's Game of Life</h1>

        <canvas id="gameCanvas" width="400" height="400"></canvas>

        <div class="controls">
            <button id="stepBtn">Step</button>
            <button id="playBtn">Play Auto-Run</button>
            <button id="randomBtn">Randomize Cells</button>
            <button id="clearBtn">Clear All</button>
        </div>

        <div class="grid-controls">
            <span>Grid Size:</span>
            <input type="number" id="gridSizeInput" value="50" min="40" max="500">
        </div>
    </div>

    <script>
        // Game state variables
        let gridState = [];
        let generationCount = 0;
        let seedRandom = false;

        // Grid dimensions (at least 400x400, but we'll use 50 for simplicity)
        const WIDTH = 500;
        const HEIGHT = 500;

        // Initialize the game
        function initGame() {
            generationCount = 0;

            // Create grid with random initial state
            for (let y = 0; y < HEIGHT; y++) {
                gridState[y] = [];
                for (let x = 0; x < WIDTH; x++) {
                    gridState[y][x] = seedRandom ? Math.random() : false;
                }
            }

            // Set up event listeners
            document.getElementById('stepBtn').addEventListener('click', () => {
                if (!seedRandom) generationCount++;
                else generationCount--;

                updateGrid();
            });

            document.getElementById('playBtn').addEventListener('click', () => {
                seedRandom = true;
                generateNewGame();
            });

            document.getElementById('randomBtn').addEventListener('click', () => {
                if (!seedRandom) generationCount++;
                else generationCount--;

                updateGrid();
            });

            document.getElementById('clearBtn').addEventListener('click', () => {
                clearAllCells();
            });
        }

        // Generate a new game state
        function generateNewGame() {
            generationCount = 0;

            for (let y = 0; y < HEIGHT; y++) {
                gridState[y] = [];
                for (let x = 0; x < WIDTH; x++) {
                    gridState[y][x] = seedRandom ? Math.random() : false;
                }
            }
        }

        // Update the grid state
        function updateGrid() {
            generationCount--;

            if (generationCount > 0) {
                const newGeneration = generateNewGame();

                // Calculate live neighbors for each cell
                const liveNeighbors = calculateLiveNeighbors(newGeneration);

                // Apply rules to create next state
                const nextState = applyRules(liveNeighbors, newGeneration);

                // Update the grid state
                const updatedGrid = [...gridState];
                updatedGrid[y][x] = nextState[x * WIDTH + y];

                gridState = updatedGrid;
            }
        }

        // Calculate live neighbors for a cell (8 directions)
        function calculateLiveNeighbors(grid) {
            const result = [];

            for (let y = 0; y < HEIGHT; y++) {
                for (let x = 0; x < WIDTH; x++) {
                    let count = 0;

                    // Check all 8 neighbors
                    for (let dy = -1; dy <= 1; dy++) {
                        for (let dx = -1; dx <= 1; dx++) {
                            if (dx === 0 && dy === 0) continue;

                            const nx = x + dx;
                            const ny = y + dy;

                            // Check bounds
                            if (nx >= 0 && nx < WIDTH && ny >= 0 && ny < HEIGHT) {
                                if (grid[ny][nx] === true) count++;
                            }
                        }
                    }

                    result.push(count);
                }
            }

            return result;
        }

        // Apply rules to create next state
        function applyRules(liveNeighbors, grid) {
            const nextState = [];

            for (let y = 0; y < HEIGHT; y++) {
                for (let x = 0; x < WIDTH; x++) {
                    let count = 0;

                    // Check all 8 neighbors
                    for (let dy = -1; dy <= 1; dy++) {
                        for (let dx = -1; dx <= 1; dx++) {
                            if (dx === 0 && dy === 0) continue;

                            const nx = x + dx;
                            const ny = y + dy;

                            // Check bounds
                            if (nx >= 0 && nx < WIDTH && ny >= 0 && ny < HEIGHT) {
                                if (grid[ny][nx] === true) count++;
                            }
                        }
                    }

                    // Apply rules: live cell with 2 or 3 neighbors survives, dead cell with 3 neighbors becomes alive
                    if (grid[y][x]) {
                        if (count >= 2 && count <= 3) nextState[x * WIDTH + y] = true;
                    } else {
                        if (count === 3) nextState[x * WIDTH + y] = true;
                    }
                }
            }

            return nextState;
        }

        // Clear all cells
        function clearAllCells() {
            gridState.forEach(row => row.fill(false));
        }

        // Initialize the game when page loads
        window.addEventListener('load', initGame);
    </script>
</body>
</html>
